from typing import List


class Solution:
    def nearestPalindromic(self, n: str) -> str:
        length = len(n)
        num = int(n)

        # Single digit: closest different palindrome is num - 1 (ties -> smaller).
        if length == 1:
            return str(num - 1)

        candidates = set()
        # All 9s, one digit shorter: 999, 99, ...
        candidates.add(10 ** (length - 1) - 1)
        # 1000..0001, one digit longer: 101, 1001, ...
        candidates.add(10 ** length + 1)

        prefix = int(n[: (length + 1) // 2])
        for p in (prefix - 1, prefix, prefix + 1):
            s = str(p)
            if length % 2 == 0:
                pal = s + s[::-1]
            else:
                pal = s + s[-2::-1]  # drop the middle digit before mirroring
            candidates.add(int(pal))

        candidates.discard(num)

        best = None
        for c in candidates:
            if best is None or (abs(c - num), c) < (abs(best - num), best):
                best = c
        return str(best)


def is_pal(x: int) -> bool:
    s = str(x)
    return x >= 0 and s == s[::-1]


def brute(n: str) -> str:
    num = int(n)
    for d in range(1, 200000):
        lo, hi = num - d, num + d
        if lo >= 0 and is_pal(lo):
            return str(lo)
        if is_pal(hi):
            return str(hi)
    return None


sol = Solution()
# Given samples
print("123 ->", sol.nearestPalindromic("123"), "(exp 121)")
print("1   ->", sol.nearestPalindromic("1"), "(exp 0)")

# Edge / known cases
for n, exp in [("10", "9"), ("11", "9"), ("99", "101"), ("1000", "999"),
               ("100", "99"), ("9", "8"), ("2", "1"), ("1213", "1221"),
               ("12321", "12221")]:
    got = sol.nearestPalindromic(n)
    print(f"{n} -> {got}  exp {exp}  {'OK' if got==exp else 'XX'}")

# Oracle cross-check on a range
import random
mismatch = 0
for _ in range(20000):
    num = random.randint(1, 9999)
    n = str(num)
    g = sol.nearestPalindromic(n)
    b = brute(n)
    if g != b:
        mismatch += 1
        print("MISMATCH", n, "got", g, "brute", b)
print("random mismatches:", mismatch)

# Big input stress (18 digits) — just ensure it runs fast & returns a palindrome
big = "9" * 18
print("18-nines ->", sol.nearestPalindromic(big))
print("max18 ->", sol.nearestPalindromic("999999999999999999"))
print("1e17 ->", sol.nearestPalindromic("100000000000000000"))
